SELECT MIN(threshold_value) AS min_threshold, MAX(threshold_value) AS max_threshold
FROM trade_configuration_thresholds
WHERE threshold_name = 'close trade quantity percentage';

SELECT config_id, entity_level
FROM trade_configurations
WHERE status = 'active';

SELECT DISTINCT instrument_type
FROM trade_activity
WHERE trade_date = '2023-05-02';

SELECT change_date
FROM trade_configuration_history
WHERE change_date = '2023-05-01';

SELECT filter_value
FROM trade_configuration_filters
WHERE filter_name = 'sym';

SELECT SUM(trade_quantity) AS total_trades
FROM trade_activity
WHERE market = 'NASDAQ';

SELECT config_id, SUM(trade_quantity) AS total_quantity
FROM trade_activity
GROUP BY config_id;

SELECT threshold_value
FROM trade_configuration_thresholds
WHERE threshold_name = 'close trade quantity percentage';
